let seq=0;let searchTimer=0;const searchCommandIcon='<svg class="icon icon-command" width="18" height="18" viewBox="0 0 24 24" aria-hidden="true" focusable="false" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M15 6v12a3 3 0 1 0 3-3H6a3 3 0 1 0 3 3V6a3 3 0 1 0-3 3h12a3 3 0 1 0-3-3"/></svg>';const searchEnterIcon='<svg class="icon icon-corner-down-left" width="18" height="18" viewBox="0 0 24 24" aria-hidden="true" focusable="false" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M20 4v7a4 4 0 0 1-4 4H4"/><path d="m9 10-5 5 5 5"/></svg>';const searchEmptyIcon='<span class="search-empty-icon" aria-hidden="true"><svg class="icon icon-search" width="18" height="18" viewBox="0 0 24 24" focusable="false" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="m21 21-4.35-4.35"/><circle cx="11" cy="11" r="7"/></svg></span>';const searchAliases={install:"getting started onboarding setup curl node",setup:"install onboarding getting started",telegram:"channels telegram groups tdlib pairing",slack:"channels slack app bot socket mode",gateway:"gateway auth heartbeat remote health restart",doctor:"gateway health heartbeat restart diagnostics",plugin:"plugins capabilities tools skills",plugins:"plugins capabilities tools skills",config:"configuration json5 env defaults",model:"models providers openai anthropic google"};function expandSearchQuery(q){const extra=q.toLowerCase().split(/\\s+/).flatMap(word=>searchAliases[word]?[searchAliases[word]]:[]);return [q,...extra].join(" ").trim()}
function searchQuery(){return input?.value.trim()||""}
function escapeSearchHtml(value){const div=document.createElement("div");div.textContent=String(value||"");return div.innerHTML}
function setSearchChrome(q){modal?.classList.toggle("has-query",!!q);if(moltySearchPrefix)moltySearchPrefix.textContent=q?"Ask Molty about":"Ask Molty";if(moltySearchTerm){moltySearchTerm.textContent=q;moltySearchTerm.hidden=!q}}
function setSearchLoading(loading){modal?.classList.toggle("is-searching",loading);results?.classList.toggle("is-loading",loading)}
function searchLoadingHtml(){return '<div class="search-loading" role="status" aria-live="polite"><span class="search-spinner"><span class="search-spinner-emoji"></span></span><span>Searching...</span></div>'}function showSearchLoading(){if(results&&!results.querySelector(".search-loading"))results.innerHTML=searchLoadingHtml()}
function searchInitialHtml(){return '<div class="search-empty">'+searchEmptyIcon+'<strong>Search the docs</strong><p>Search setup, commands, integrations, and config docs.</p></div>'}
function searchUnavailableHtml(){return '<div class="search-empty search-unavailable">'+searchEmptyIcon+'<strong>Search index unavailable.</strong><p>Build the preview search index to enable results.</p></div>'}
function canAskMoltyFromSearch(){return Boolean(moltySearch&&window.OPENCLAW_DOCS_ASK_MOLTY)}
function setActiveSearchResult(index){if(!searchItems.length){searchActiveIndex=-1;return}searchActiveIndex=(index+searchItems.length)%searchItems.length;for(const node of results?.querySelectorAll("[data-search-result-index]")||[]){const active=Number(node.dataset.searchResultIndex)===searchActiveIndex;node.classList.toggle("active",active);node.setAttribute("aria-selected",String(active));if(active)node.scrollIntoView({block:"nearest"})}}
function searchResultHtml(item,index){const meta=item.meta||{};const metaParts=[meta.category,meta.section].filter(Boolean).map(part=>'<span>'+escapeSearchHtml(part)+'</span>').join("");return '<a class="search-result" role="option" aria-selected="false" data-search-result-index="'+index+'" href="'+withBase(item.url)+'">'+(metaParts?'<div class="search-result-meta">'+metaParts+'</div>':"")+'<strong>'+escapeSearchHtml(meta.title||item.url)+'</strong><span class="search-result-enter" aria-hidden="true">'+searchEnterIcon+'</span><p>'+(item.excerpt||"")+"</p></a>"}
function searchEmptyHtml(q){const fallback=canAskMoltyFromSearch()?'<p>Try another search, or <span class="search-empty-kbd" aria-label="Command Enter">'+searchCommandIcon+searchEnterIcon+'</span> to ask Molty directly.</p>':'<p>Try another search or use the docs navigation.</p>';return '<div class="search-empty">'+searchEmptyIcon+'<strong>No matches for “'+escapeSearchHtml(q)+'”.</strong>'+fallback+'</div>'}
